// === ANIMATED LINE REVEAL ===
const LineReveal = ({ children, delay = 0, className = '', style = {} }) => (
  <div style={{ overflow: 'hidden', ...style }} className={className}>
    <motion.div
      initial={{ y: '110%' }}
      animate={{ y: 0 }}
      transition={{ duration: 1, delay, ease }}
    >
      {children}
    </motion.div>
  </div>
);

